void Resizer::initDesignArea()
{
  design_area_ = 0.0;
  for (dbInst* inst : block_->getInsts()) {
    dbMaster* master = inst->getMaster();
    // Don't count fillers otherwise you'll always get 100% utilization
    if (!master->isFiller()) {
      design_area_ += area(master);
